{
  "name": "Aprova JK - Preparatório Vigia e Motorista",
  "description": "Sistema inteligente de estudo focado na banca Instituto JK para cargos de Vigia e Motorista Categoria D, com geração de questões via IA e análise de desempenho."
}

export enum Role {
  VIGIA = 'Vigia',
  MOTORISTA = 'Motorista Categoria D',
}

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctIndex: number;
  explanation: string;
  topic: string;
}

export interface AnswerAttempt {
  questionId: string;
  selectedIndex: number;
  timeSpentSeconds: number;
  isCorrect: boolean;
}

export interface QuizSession {
  questions: Question[];
  answers: AnswerAttempt[];
  startTime: number;
  endTime?: number;
}

export interface UploadedFile {
  name: string;
  mimeType: string;
  data: string; // Base64
}

export enum AppView {
  HOME = 'HOME',
  QUIZ = 'QUIZ',
  RESULTS = 'RESULTS',
  LOADING = 'LOADING',
}

export interface StrategicAnalysis {
  strengths: string[];
  weaknesses: string[];
  bancaPattern: string;
  recommendations: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Question, Role, UploadedFile, StrategicAnalysis, AnswerAttempt } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Schema for generating questions
const questionSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      text: { type: Type.STRING, description: "The question stem/statement." },
      options: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING },
        description: "List of 4 or 5 answer choices."
      },
      correctIndex: { type: Type.INTEGER, description: "Zero-based index of the correct answer." },
      explanation: { type: Type.STRING, description: "Detailed explanation of why the answer is correct." },
      topic: { type: Type.STRING, description: "The subject (e.g., Portuguese, Math, Traffic Law)." }
    },
    required: ["text", "options", "correctIndex", "explanation", "topic"],
  },
};

export const generateQuestions = async (
  role: Role, 
  files: UploadedFile[], 
  extraContext: string
): Promise<Question[]> => {

  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    Você é um especialista em concursos públicos no Brasil, especificamente focado na banca 'Instituto JK' (Instituto Social da Cidadania Juscelino Kubitschek).
    Seu objetivo é preparar candidatos para os cargos de ${role}.
    Gere questões de múltipla escolha que imitem o estilo, dificuldade e "pegadinhas" desta banca.
    Para Motorista, foque muito em CTB (Código de Trânsito Brasileiro), Direção Defensiva e Mecânica Básica.
    Para Vigia, foque em Português, Matemática Básica e Noções de Segurança.
    Use os documentos fornecidos como base se houver, caso contrário, use seu conhecimento sobre a banca e o cargo.
  `;

  const prompt = `
    Gere 5 questões de concurso para o cargo de ${role}.
    Contexto adicional do usuário: "${extraContext}".
    Certifique-se de que o nível de dificuldade seja compatível com Nível Fundamental ou Médio, conforme o cargo.
    Retorne apenas o JSON.
  `;

  const parts: any[] = [{ text: prompt }];

  // Attach files if they exist
  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: file.data
      }
    });
  });

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: questionSchema,
        tools: [{ googleSearch: {} }], // Use search to find specific Banca JK style if files aren't enough
      },
    });

    if (response.text) {
      const rawQuestions = JSON.parse(response.text);
      return rawQuestions.map((q: any, index: number) => ({
        ...q,
        id: `q-${Date.now()}-${index}`
      }));
    }
    return [];
  } catch (error) {
    console.error("Error generating questions:", error);
    throw new Error("Falha ao gerar questões. Tente novamente.");
  }
};

export const analyzePerformanceAndPattern = async (
  role: Role,
  answers: AnswerAttempt[],
  questions: Question[]
): Promise<StrategicAnalysis> => {
  const model = "gemini-3-flash-preview";

  // Construct a history of what happened
  const performanceSummary = questions.map((q, idx) => {
    const ans = answers.find(a => a.questionId === q.id);
    return `Questão: ${q.text} | Tópico: ${q.topic} | Correta: ${ans?.isCorrect} | Tempo: ${ans?.timeSpentSeconds}s`;
  }).join("\n");

  const prompt = `
    Analise o desempenho deste candidato para o cargo de ${role} na banca Instituto JK.

    Dados do Simulado:
    ${performanceSummary}

    Tarefas:
    1. Identifique pontos fortes e fracos baseados nos tópicos.
    2. Explique o "Padrão da Banca" (Instituto JK) para este cargo (use o Google Search se precisar atualizar seu conhecimento sobre provas recentes desta banca). O que eles mais cobram? Como são as pegadinhas?
    3. Dê recomendações práticas de estudo para passar.
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
      weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
      bancaPattern: { type: Type.STRING, description: "Detailed analysis of the exam board style." },
      recommendations: { type: Type.STRING, description: "Study plan advice." }
    },
    required: ["strengths", "weaknesses", "bancaPattern", "recommendations"]
  };

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        tools: [{ googleSearch: {} }] // Essential for finding the specific banca pattern
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as StrategicAnalysis;
    }
    throw new Error("No analysis returned");
  } catch (error) {
    console.error("Error analyzing pattern:", error);
    return {
      strengths: [],
      weaknesses: [],
      bancaPattern: "Não foi possível analisar o padrão no momento.",
      recommendations: "Continue estudando os tópicos onde errou mais questões."
    };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, AnswerAttempt } from '../types';
import { CheckCircle, XCircle, Clock } from 'lucide-react';

interface QuizInterfaceProps {
  questions: Question[];
  onComplete: (answers: AnswerAttempt[]) => void;
}

const QuizInterface: React.FC<QuizInterfaceProps> = ({ questions, onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [answers, setAnswers] = useState<AnswerAttempt[]>([]);
  const [showExplanation, setShowExplanation] = useState(false);
  const [timeSeconds, setTimeSeconds] = useState(0);

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    timerRef.current = window.setInterval(() => {
      setTimeSeconds(prev => prev + 1);
    }, 1000);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [currentIndex]);

  const currentQuestion = questions[currentIndex];

  const handleConfirm = () => {
    if (selectedOption === null) return;

    if (timerRef.current) clearInterval(timerRef.current);

    const isCorrect = selectedOption === currentQuestion.correctIndex;
    const newAttempt: AnswerAttempt = {
      questionId: currentQuestion.id,
      selectedIndex: selectedOption,
      timeSpentSeconds: timeSeconds,
      isCorrect
    };

    setAnswers(prev => [...prev, newAttempt]);
    setShowExplanation(true);
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowExplanation(false);
      setTimeSeconds(0);
    } else {
      onComplete(answers);
    }
  };

  const isLastQuestion = currentIndex === questions.length - 1;

  return (
    <div className="max-w-3xl mx-auto w-full">
      <div className="bg-white rounded-xl shadow-lg overflow-hidden">
        {/* Progress Bar */}
        <div className="w-full bg-gray-200 h-2">
          <div 
            className="bg-blue-600 h-2 transition-all duration-300" 
            style={{ width: `${((currentIndex) / questions.length) * 100}%` }}
          />
        </div>

        <div className="p-6 md:p-8">
          <div className="flex justify-between items-center mb-6">
            <span className="text-sm font-semibold text-gray-500 uppercase tracking-wide">
              Questão {currentIndex + 1} de {questions.length}
            </span>
            <div className="flex items-center text-gray-600 text-sm font-mono bg-gray-100 px-3 py-1 rounded-full">
              <Clock className="w-4 h-4 mr-2" />
              {Math.floor(timeSeconds / 60)}:{(timeSeconds % 60).toString().padStart(2, '0')}
            </div>
          </div>

          <div className="mb-2">
            <span className="inline-block bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded mb-2 font-semibold">
              {currentQuestion.topic}
            </span>
            <h2 className="text-xl md:text-2xl font-bold text-gray-800 leading-relaxed">
              {currentQuestion.text}
            </h2>
          </div>

          <div className="space-y-3 mt-6">
            {currentQuestion.options.map((option, idx) => {
              let optionClass = "border-2 p-4 rounded-lg cursor-pointer transition-all flex items-center ";

              if (showExplanation) {
                if (idx === currentQuestion.correctIndex) {
                  optionClass += "border-green-500 bg-green-50 text-green-900";
                } else if (idx === selectedOption) {
                  optionClass += "border-red-500 bg-red-50 text-red-900";
                } else {
                  optionClass += "border-gray-200 opacity-50";
                }
              } else {
                if (selectedOption === idx) {
                  optionClass += "border-blue-500 bg-blue-50 ring-1 ring-blue-500";
                } else {
                  optionClass += "border-gray-200 hover:border-blue-300 hover:bg-gray-50";
                }
              }

              return (
                <div 
                  key={idx} 
                  onClick={() => !showExplanation && setSelectedOption(idx)}
                  className={optionClass}
                >
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 flex-shrink-0 ${
                    showExplanation && idx === currentQuestion.correctIndex ? 'border-green-500 bg-green-500 text-white' :
                    showExplanation && idx === selectedOption ? 'border-red-500 bg-red-500 text-white' :
                    selectedOption === idx ? 'border-blue-500 bg-blue-500 text-white' : 'border-gray-300'
                  }`}>
                    {showExplanation && idx === currentQuestion.correctIndex && <CheckCircle className="w-4 h-4" />}
                    {showExplanation && idx === selectedOption && idx !== currentQuestion.correctIndex && <XCircle className="w-4 h-4" />}
                    {!showExplanation && selectedOption === idx && <div className="w-2 h-2 bg-white rounded-full" />}
                  </div>
                  <span className="text-base">{option}</span>
                </div>
              );
            })}
          </div>

          {showExplanation && (
            <div className="mt-6 p-4 bg-blue-50 rounded-lg border border-blue-100 animate-fade-in">
              <h3 className="font-bold text-blue-900 mb-2">Explicação:</h3>
              <p className="text-blue-800 text-sm leading-relaxed">{currentQuestion.explanation}</p>
            </div>
          )}
        </div>

        <div className="bg-gray-50 p-6 border-t border-gray-100 flex justify-end">
          {!showExplanation ? (
            <button
              onClick={handleConfirm}
              disabled={selectedOption === null}
              className={`px-8 py-3 rounded-lg font-bold text-white transition-all transform ${
                selectedOption === null 
                  ? 'bg-gray-300 cursor-not-allowed' 
                  : 'bg-blue-600 hover:bg-blue-700 hover:-translate-y-1 shadow-md hover:shadow-lg'
              }`}
            >
              Responder
            </button>
          ) : (
            <button
              onClick={handleNext}
              className="px-8 py-3 rounded-lg font-bold text-white bg-green-600 hover:bg-green-700 shadow-md hover:shadow-lg transition-all transform hover:-translate-y-1"
            >
              {isLastQuestion ? 'Finalizar Simulado' : 'Próxima Questão'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default QuizInterface;

import React, { useState, useCallback } from 'react';
import { UploadedFile, Role } from '../types';
import { UploadCloud, FileText, Trash2, BookOpen } from 'lucide-react';

interface UploadSectionProps {
  onStart: (role: Role, files: UploadedFile[], context: string) => void;
  isLoading: boolean;
}

const UploadSection: React.FC<UploadSectionProps> = ({ onStart, isLoading }) => {
  const [role, setRole] = useState<Role>(Role.VIGIA);
  const [files, setFiles] = useState<UploadedFile[]>([]);
  const [context, setContext] = useState('');

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: UploadedFile[] = [];

      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        if (file.type === 'application/pdf' || file.type === 'text/plain') {
          const reader = new FileReader();

          const filePromise = new Promise<UploadedFile>((resolve) => {
            reader.onload = (event) => {
              const base64 = (event.target?.result as string).split(',')[1];
              resolve({
                name: file.name,
                mimeType: file.type,
                data: base64
              });
            };
          });

          reader.readAsDataURL(file);
          newFiles.push(await filePromise);
        }
      }
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-xl animate-fade-in">
      <div className="text-center mb-8">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-100 rounded-full mb-4">
          <BookOpen className="w-8 h-8 text-blue-600" />
        </div>
        <h2 className="text-3xl font-bold text-gray-800">Configurar Simulado</h2>
        <p className="text-gray-500 mt-2">Personalize seu estudo para o Instituto JK</p>
      </div>

      <div className="space-y-6">

        {/* Role Selection */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Cargo Pretendido</label>
          <div className="grid grid-cols-2 gap-4">
            <button
              onClick={() => setRole(Role.VIGIA)}
              className={`p-4 rounded-xl border-2 transition-all text-center ${
                role === Role.VIGIA 
                  ? 'border-blue-500 bg-blue-50 text-blue-700 font-bold' 
                  : 'border-gray-200 text-gray-600 hover:border-blue-200'
              }`}
            >
              🛡️ Vigia
            </button>
            <button
              onClick={() => setRole(Role.MOTORISTA)}
              className={`p-4 rounded-xl border-2 transition-all text-center ${
                role === Role.MOTORISTA 
                  ? 'border-blue-500 bg-blue-50 text-blue-700 font-bold' 
                  : 'border-gray-200 text-gray-600 hover:border-blue-200'
              }`}
            >
              🚌 Motorista Cat. D
            </button>
          </div>
        </div>

        {/* File Upload */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Material de Estudo (PDFs)
            <span className="text-gray-400 font-normal ml-2">(Opcional)</span>
          </label>

          <div className="border-2 border-dashed border-gray-300 rounded-xl p-6 text-center hover:bg-gray-50 transition-colors relative">
            <input
              type="file"
              multiple
              accept="application/pdf"
              onChange={handleFileChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
            <UploadCloud className="w-10 h-10 text-gray-400 mx-auto mb-2" />
            <p className="text-sm text-gray-600 font-medium">Clique ou arraste seus PDFs aqui</p>
            <p className="text-xs text-gray-400 mt-1">Usaremos isso para gerar questões específicas</p>
          </div>

          {/* File List */}
          {files.length > 0 && (
            <div className="mt-4 space-y-2">
              {files.map((file, idx) => (
                <div key={idx} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-200">
                  <div className="flex items-center space-x-3">
                    <FileText className="w-5 h-5 text-blue-500" />
                    <span className="text-sm text-gray-700 truncate max-w-[200px]">{file.name}</span>
                  </div>
                  <button onClick={() => removeFile(idx)} className="text-red-400 hover:text-red-600 transition">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Extra Context */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Instruções Extras ou Links</label>
          <textarea
            value={context}
            onChange={(e) => setContext(e.target.value)}
            placeholder="Ex: Foque em questões sobre direção defensiva, ou use o link https://..."
            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none min-h-[100px]"
          />
        </div>

        <button
          onClick={() => onStart(role, files, context)}
          disabled={isLoading}
          className={`w-full py-4 rounded-xl font-bold text-lg text-white shadow-lg transition-all transform hover:-translate-y-1 ${
            isLoading 
              ? 'bg-gray-400 cursor-wait' 
              : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700'
          }`}
        >
          {isLoading ? (
            <span className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Gerando Questões com IA...
            </span>
          ) : 'Começar Simulado'}
        </button>
      </div>
    </div>
  );
};

export default UploadSection;

import React, { useState } from 'react';
import { AppView, Question, AnswerAttempt, UploadedFile, Role, StrategicAnalysis } from './types';
import UploadSection from './components/UploadSection';
import QuizInterface from './components/QuizInterface';
import ResultsView from './components/ResultsView';
import { generateQuestions, analyzePerformanceAndPattern } from './services/geminiService';
import { GraduationCap } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [loading, setLoading] = useState(false);
  const [role, setRole] = useState<Role>(Role.VIGIA);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [answers, setAnswers] = useState<AnswerAttempt[]>([]);
  const [analysis, setAnalysis] = useState<StrategicAnalysis | null>(null);

  const handleStartQuiz = async (selectedRole: Role, files: UploadedFile[], context: string) => {
    setLoading(true);
    setRole(selectedRole);
    try {
      const generatedQuestions = await generateQuestions(selectedRole, files, context);
      if (generatedQuestions.length > 0) {
        setQuestions(generatedQuestions);
        setView(AppView.QUIZ);
      } else {
        alert("Não foi possível gerar questões. Tente adicionar mais contexto ou arquivos.");
      }
    } catch (error) {
      console.error(error);
      alert("Erro ao conectar com a IA. Verifique sua conexão ou tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const handleQuizComplete = async (completedAnswers: AnswerAttempt[]) => {
    setAnswers(completedAnswers);
    setView(AppView.RESULTS);

    // Trigger async analysis without blocking the UI transition
    analyzePerformanceAndPattern(role, completedAnswers, questions).then(result => {
      setAnalysis(result);
    });
  };

  const handleRestart = () => {
    setQuestions([]);
    setAnswers([]);
    setAnalysis(null);
    setView(AppView.HOME);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans text-gray-800">

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="bg-gradient-to-tr from-blue-600 to-indigo-600 p-2 rounded-lg">
              <GraduationCap className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-700 to-indigo-700">
                Aprova JK
              </h1>
              <p className="text-xs text-gray-500 font-medium tracking-wide">Vigia & Motorista</p>
            </div>
          </div>
          {view !== AppView.HOME && (
            <button 
              onClick={handleRestart}
              className="text-sm font-medium text-gray-500 hover:text-blue-600 transition-colors"
            >
              Voltar ao Início
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow p-4 md:p-8">
        {view === AppView.HOME && (
          <UploadSection onStart={handleStartQuiz} isLoading={loading} />
        )}

        {view === AppView.QUIZ && (
          <QuizInterface 
            questions={questions} 
            onComplete={handleQuizComplete} 
          />
        )}

        {view === AppView.RESULTS && (
          <ResultsView 
            answers={answers} 
            questions={questions} 
            analysis={analysis} 
            role={role}
            onRestart={handleRestart}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-gray-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center text-gray-400 text-sm">
          <p>© {new Date().getFullYear()} Aprova JK. Sistema Inteligente de Estudos.</p>
          <p className="mt-1 text-xs">Desenvolvido com Google Gemini</p>
        </div>
      </footer>

    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { AppView, Question, AnswerAttempt, UploadedFile, Role, StrategicAnalysis } from './types';
import UploadSection from './components/UploadSection';
import QuizInterface from './components/QuizInterface';
import ResultsView from './components/ResultsView';
import { generateQuestions, analyzePerformanceAndPattern } from './services/geminiService';
import { GraduationCap, Moon, Sun } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [loading, setLoading] = useState(false);
  const [role, setRole] = useState<Role>(Role.VIGIA);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [answers, setAnswers] = useState<AnswerAttempt[]>([]);
  const [analysis, setAnalysis] = useState<StrategicAnalysis | null>(null);

  // Initialize dark mode from system preference or default to false
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return true;
    }
    return false;
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
  };

  const handleStartQuiz = async (selectedRole: Role, files: UploadedFile[], context: string) => {
    setLoading(true);
    setRole(selectedRole);
    try {
      const generatedQuestions = await generateQuestions(selectedRole, files, context);
      if (generatedQuestions.length > 0) {
        setQuestions(generatedQuestions);
        setView(AppView.QUIZ);
      } else {
        alert("Não foi possível gerar questões. Tente adicionar mais contexto ou arquivos.");
      }
    } catch (error) {
      console.error(error);
      alert("Erro ao conectar com a IA. Verifique sua conexão ou tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const handleQuizComplete = async (completedAnswers: AnswerAttempt[]) => {
    setAnswers(completedAnswers);
    setView(AppView.RESULTS);

    // Trigger async analysis without blocking the UI transition
    analyzePerformanceAndPattern(role, completedAnswers, questions).then(result => {
      setAnalysis(result);
    });
  };

  const handleRestart = () => {
    setQuestions([]);
    setAnswers([]);
    setAnalysis(null);
    setView(AppView.HOME);
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex flex-col font-sans text-gray-800 dark:text-gray-100 transition-colors duration-300">

      {/* Header */}
      <header className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 sticky top-0 z-10 transition-colors duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="bg-gradient-to-tr from-blue-600 to-indigo-600 p-2 rounded-lg">
              <GraduationCap className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-700 to-indigo-700 dark:from-blue-400 dark:to-indigo-400">
                Aprova JK
              </h1>
              <p className="text-xs text-gray-500 dark:text-gray-400 font-medium tracking-wide">Vigia & Motorista</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button
              onClick={toggleTheme}
              className="p-2 rounded-full text-gray-500 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-700 transition-colors"
              aria-label="Toggle Dark Mode"
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            {view !== AppView.HOME && (
              <button 
                onClick={handleRestart}
                className="text-sm font-medium text-gray-500 hover:text-blue-600 dark:text-gray-400 dark:hover:text-blue-400 transition-colors"
              >
                Voltar ao Início
              </button>
            )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow p-4 md:p-8">
        {view === AppView.HOME && (
          <UploadSection onStart={handleStartQuiz} isLoading={loading} />
        )}

        {view === AppView.QUIZ && (
          <QuizInterface 
            questions={questions} 
            onComplete={handleQuizComplete} 
          />
        )}

        {view === AppView.RESULTS && (
          <ResultsView 
            answers={answers} 
            questions={questions} 
            analysis={analysis} 
            role={role}
            onRestart={handleRestart}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 py-6 mt-auto transition-colors duration-300">
        <div className="max-w-7xl mx-auto px-4 text-center text-gray-400 dark:text-gray-500 text-sm">
          <p>© {new Date().getFullYear()} Aprova JK. Sistema Inteligente de Estudos.</p>
          <p className="mt-1 text-xs">Desenvolvido com Google Gemini</p>
        </div>
      </footer>

    </div>
  );
};

