import { UploadedFile, HistoryItem } from '../types';

const DB_NAME = 'AprovaJK_DB';
const DB_VERSION = 1;
const STORE_FILES = 'files';
const STORE_HISTORY = 'history';

// Helper to open DB
const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_FILES)) {
        db.createObjectStore(STORE_FILES, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(STORE_HISTORY)) {
        db.createObjectStore(STORE_HISTORY, { keyPath: 'id', autoIncrement: true });
      }
    };

    request.onsuccess = (event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };

    request.onerror = (event) => {
      reject((event.target as IDBOpenDBRequest).error);
    };
  });
};

export const saveFile = async (file: UploadedFile): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_FILES, 'readwrite');
    const store = transaction.objectStore(STORE_FILES);
    // Ensure ID exists
    const fileToSave = { ...file, id: file.name + '-' + Date.now(), dateAdded: Date.now() };
    const request = store.put(fileToSave);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const getFiles = async (): Promise<UploadedFile[]> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_FILES, 'readonly');
    const store = transaction.objectStore(STORE_FILES);
    const request = store.getAll();

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const deleteFile = async (id: string): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_FILES, 'readwrite');
    const store = transaction.objectStore(STORE_FILES);
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const saveHistory = async (item: Omit<HistoryItem, 'id'>): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_HISTORY, 'readwrite');
    const store = transaction.objectStore(STORE_HISTORY);
    const request = store.add(item);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const getHistory = async (): Promise<HistoryItem[]> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_HISTORY, 'readonly');
    const store = transaction.objectStore(STORE_HISTORY);
    const request = store.getAll();

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Question, Role, UploadedFile, StrategicAnalysis, AnswerAttempt } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Schema for generating questions
const questionSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      text: { type: Type.STRING, description: "The question stem/statement." },
      options: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING },
        description: "List of 4 or 5 answer choices."
      },
      correctIndex: { type: Type.INTEGER, description: "Zero-based index of the correct answer." },
      explanation: { type: Type.STRING, description: "Detailed explanation of why the answer is correct." },
      topic: { type: Type.STRING, description: "The subject (e.g., Portuguese, Math, Traffic Law)." }
    },
    required: ["text", "options", "correctIndex", "explanation", "topic"],
  },
};

export const generateQuestions = async (
  role: Role, 
  files: UploadedFile[], 
  extraContext: string
): Promise<Question[]> => {

  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    Você é um especialista em concursos públicos no Brasil, especificamente focado na banca 'Instituto JK' (Instituto Social da Cidadania Juscelino Kubitschek).
    Seu objetivo é preparar candidatos para os cargos de ${role}.
    Gere questões de múltipla escolha que imitem o estilo, dificuldade e "pegadinhas" desta banca.
    Para Motorista, foque muito em CTB (Código de Trânsito Brasileiro), Direção Defensiva e Mecânica Básica.
    Para Vigia, foque em Português, Matemática Básica e Noções de Segurança.
    Use os documentos fornecidos como base se houver, caso contrário, use seu conhecimento sobre a banca e o cargo.
    Gere questões ÚNICAS, evite repetições.
  `;

  // To get 40 questions reliably, we will make parallel requests.
  // Asking for 40 at once often causes timeouts or truncated JSON.
  // We will do 4 requests of 10 questions each.

  const totalQuestions = 40;
  const batchSize = 10;
  const batches = totalQuestions / batchSize;

  const promises = [];

  for (let i = 0; i < batches; i++) {
    const prompt = `
      Gere ${batchSize} questões de concurso para o cargo de ${role}.
      Lote ${i + 1} de ${batches}. Tente cobrir tópicos diferentes do usual.
      Contexto adicional do usuário: "${extraContext}".
      Certifique-se de que o nível de dificuldade seja compatível com Nível Fundamental ou Médio, conforme o cargo.
      Retorne apenas o JSON.
    `;

    const parts: any[] = [{ text: prompt }];

    // Attach files if they exist (Gemini handles multiple files well)
    files.forEach(file => {
      parts.push({
        inlineData: {
          mimeType: file.mimeType,
          data: file.data
        }
      });
    });

    promises.push(
      ai.models.generateContent({
        model: model,
        contents: { parts },
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: questionSchema,
          // Limit thinking budget to speed up batch generation, focusing on volume
          thinkingConfig: { thinkingBudget: 1024 }, 
        },
      }).catch(e => {
        console.error(`Batch ${i} failed`, e);
        return null;
      })
    );
  }

  try {
    const results = await Promise.all(promises);
    let allQuestions: Question[] = [];

    results.forEach((response) => {
      if (response && response.text) {
        try {
          const batchQuestions = JSON.parse(response.text);
          allQuestions = [...allQuestions, ...batchQuestions];
        } catch (e) {
          console.error("Failed to parse batch json", e);
        }
      }
    });

    // Assign unique IDs
    return allQuestions.map((q: any, index: number) => ({
      ...q,
      id: `q-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating questions:", error);
    throw new Error("Falha ao gerar questões. Tente novamente.");
  }
};

export const analyzePerformanceAndPattern = async (
  role: Role,
  answers: AnswerAttempt[],
  questions: Question[]
): Promise<StrategicAnalysis> => {
  const model = "gemini-3-flash-preview";

  // Summarize to avoid token limits if 40 questions
  const correctCount = answers.filter(a => a.isCorrect).length;
  const total = questions.length;

  // Group by topic
  const topicPerformance: Record<string, { total: number, correct: number }> = {};
  questions.forEach(q => {
    if (!topicPerformance[q.topic]) topicPerformance[q.topic] = { total: 0, correct: 0 };
    topicPerformance[q.topic].total++;
    const isCorrect = answers.find(a => a.questionId === q.id)?.isCorrect;
    if (isCorrect) topicPerformance[q.topic].correct++;
  });

  const topicSummary = Object.entries(topicPerformance)
    .map(([topic, stats]) => `- ${topic}: ${stats.correct}/${stats.total} acertos`)
    .join("\n");

  const prompt = `
    Analise o desempenho deste candidato para o cargo de ${role} na banca Instituto JK.

    Resumo Geral: ${correctCount} acertos de ${total} questões.
    Desempenho por Tópico:
    ${topicSummary}

    Tarefas:
    1. Identifique pontos fortes e fracos baseados nos tópicos.
    2. Explique o "Padrão da Banca" (Instituto JK) para este cargo. O que eles mais cobram? Como são as pegadinhas?
    3. Dê recomendações práticas de estudo para passar.
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
      weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
      bancaPattern: { type: Type.STRING, description: "Detailed analysis of the exam board style." },
      recommendations: { type: Type.STRING, description: "Study plan advice." }
    },
    required: ["strengths", "weaknesses", "bancaPattern", "recommendations"]
  };

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        tools: [{ googleSearch: {} }]
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as StrategicAnalysis;
    }
    throw new Error("No analysis returned");
  } catch (error) {
    console.error("Error analyzing pattern:", error);
    return {
      strengths: [],
      weaknesses: [],
      bancaPattern: "Não foi possível analisar o padrão no momento.",
      recommendations: "Continue estudando os tópicos onde errou mais questões."
    };
  }
};

