import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Question, Role, UploadedFile, StrategicAnalysis, AnswerAttempt } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Schema for generating questions
const questionSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      text: { type: Type.STRING, description: "The question stem/statement." },
      options: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING },
        description: "List of 4 or 5 answer choices."
      },
      correctIndex: { type: Type.INTEGER, description: "Zero-based index of the correct answer." },
      explanation: { type: Type.STRING, description: "Detailed, step-by-step didactic explanation." },
      topic: { type: Type.STRING, description: "The subject (e.g., Português, Matemática, Legislação)." }
    },
    required: ["text", "options", "correctIndex", "explanation", "topic"],
  },
};

export const generateQuestions = async (
  role: Role, 
  files: UploadedFile[], 
  extraContext: string
): Promise<Question[]> => {

  const model = "gemini-3-flash-preview";

  // Instruções reforçadas para didática e busca
  const systemInstruction = `
    Você é um professor particular experiente em concursos da banca 'Instituto JK', preparando um aluno para o cargo de ${role}.

    SUA MISSÃO:
    1. Gerar questões que simulem fielmente a banca Instituto JK. Use a ferramenta de busca para encontrar o estilo real deles.
    2. O gabarito/explicação deve ser EXTREMAMENTE DIDÁTICO, "como se estivesse ensinando uma criança" ou um leigo total.

    REGRAS PARA A EXPLICAÇÃO (GABARITO):
    - SE FOR MATEMÁTICA: Não diga apenas a resposta. Arme a conta, mostre a soma, subtração, regra de três passo a passo. Exemplo: "Primeiro somamos X + Y...".
    - SE FOR LEGISLAÇÃO (Motorista): Cite o artigo do CTB, mas explique com um exemplo prático do dia a dia do motorista.
    - SE FOR PORTUGUÊS: Explique a regra gramatical de forma simples, mostrando por que as outras opções estão erradas.

    TÓPICOS PRINCIPAIS:
    - Motorista: CTB, Direção Defensiva, Mecânica Básica, Primeiros Socorros.
    - Vigia: Português, Matemática Básica, Atualidades, Noções de Segurança Patrimonial.
  `;

  const totalQuestions = 40;
  const batchSize = 10;
  const batches = totalQuestions / batchSize;

  const promises = [];

  for (let i = 0; i < batches; i++) {
    const prompt = `
      Gere ${batchSize} questões INÉDITAS para ${role} focadas na banca Instituto JK.
      Lote ${i + 1} de ${batches}.

      USE A BUSCA DO GOOGLE (googleSearch) para encontrar questões recentes ou similares aplicadas por essa banca.

      Contexto do usuário: "${extraContext}".

      Importante: A explicação deve ser detalhada e educativa. O usuário precisa aprender lendo a resposta.
    `;

    const parts: any[] = [{ text: prompt }];

    files.forEach(file => {
      parts.push({
        inlineData: {
          mimeType: file.mimeType,
          data: file.data
        }
      });
    });

    promises.push(
      ai.models.generateContent({
        model: model,
        contents: { parts },
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: questionSchema,
          tools: [{ googleSearch: {} }], // Busca ativa ativada
          thinkingConfig: { thinkingBudget: 2048 }, // Aumentado para garantir raciocínio na explicação
        },
      }).catch(e => {
        console.error(`Batch ${i} failed`, e);
        return null;
      })
    );
  }

  try {
    const results = await Promise.all(promises);
    let allQuestions: Question[] = [];

    results.forEach((response) => {
      if (response && response.text) {
        try {
          const batchQuestions = JSON.parse(response.text);
          allQuestions = [...allQuestions, ...batchQuestions];
        } catch (e) {
          console.error("Failed to parse batch json", e);
        }
      }
    });

    return allQuestions.map((q: any, index: number) => ({
      ...q,
      id: `q-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating questions:", error);
    throw new Error("Falha ao gerar questões. Tente novamente.");
  }
};

export const analyzePerformanceAndPattern = async (
  role: Role,
  answers: AnswerAttempt[],
  questions: Question[]
): Promise<StrategicAnalysis> => {
  const model = "gemini-3-flash-preview";

  const correctCount = answers.filter(a => a.isCorrect).length;
  const total = questions.length;

  const topicPerformance: Record<string, { total: number, correct: number }> = {};
  questions.forEach(q => {
    // Normalize topic names to avoid "Matemática" vs "Matematica" duplication
    const topic = q.topic.trim(); 
    if (!topicPerformance[topic]) topicPerformance[topic] = { total: 0, correct: 0 };
    topicPerformance[topic].total++;
    const isCorrect = answers.find(a => a.questionId === q.id)?.isCorrect;
    if (isCorrect) topicPerformance[topic].correct++;
  });

  const topicSummary = Object.entries(topicPerformance)
    .map(([topic, stats]) => `- ${topic}: ${stats.correct}/${stats.total} acertos (${Math.round(stats.correct/stats.total*100)}%)`)
    .join("\n");

  const prompt = `
    Aja como um coach de concursos. Analise o desempenho:

    Cargo: ${role}
    Banca Alvo: Instituto JK

    Dados:
    Acertos Totais: ${correctCount} de ${total}
    Por Matéria:
    ${topicSummary}

    1. Identifique os pontos críticos. Onde o aluno vai reprovar se não melhorar?
    2. Pesquise sobre a banca Instituto JK. Qual o estilo deles? (Texto longo? Pegadinha? Lei seca?). Explique isso no campo 'bancaPattern'.
    3. Crie um plano de ação prático no 'recommendations'. Diga exatamente o que estudar.
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
      weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
      bancaPattern: { type: Type.STRING, description: "Detailed analysis of the exam board style." },
      recommendations: { type: Type.STRING, description: "Study plan advice." }
    },
    required: ["strengths", "weaknesses", "bancaPattern", "recommendations"]
  };

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        tools: [{ googleSearch: {} }]
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as StrategicAnalysis;
    }
    throw new Error("No analysis returned");
  } catch (error) {
    console.error("Error analyzing pattern:", error);
    return {
      strengths: [],
      weaknesses: [],
      bancaPattern: "Não foi possível analisar o padrão no momento.",
      recommendations: "Continue estudando os tópicos onde errou mais questões."
    };
  }
};

export const getTutorResponse = async (
  question: Question,
  userAnswerIndex: number | null,
  userQuery: string,
  history: string
): Promise<string> => {
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    Você é um professor particular paciente e didático.
    O aluno está com dúvida em uma questão de concurso (Banca Instituto JK).

    Questão: "${question.text}"
    Opções: ${JSON.stringify(question.options)}
    Correta: ${question.options[question.correctIndex]}
    O aluno marcou: ${userAnswerIndex !== null ? question.options[userAnswerIndex] : "Não respondeu"}

    Se o aluno perguntar "Por que errei?", explique o erro específico da opção dele.
    Use linguagem simples, analogias e exemplos práticos. Seja breve e direto.
  `;

  const response = await ai.models.generateContent({
    model: model,
    contents: `Histórico da conversa:\n${history}\n\nAluno: ${userQuery}`,
    config: {
      systemInstruction: systemInstruction,
    },
  });

  return response.text || "Desculpe, não consegui gerar uma explicação agora.";
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, AnswerAttempt, ChatMessage } from '../types';
import { CheckCircle, XCircle, Clock, MessageCircle, Send, X, Bot } from 'lucide-react';
import { getTutorResponse } from '../services/geminiService';

interface QuizInterfaceProps {
  questions: Question[];
  onComplete: (answers: AnswerAttempt[]) => void;
}

const QuizInterface: React.FC<QuizInterfaceProps> = ({ questions, onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [answers, setAnswers] = useState<AnswerAttempt[]>([]);
  const [showExplanation, setShowExplanation] = useState(false);
  const [timeSeconds, setTimeSeconds] = useState(0);

  // Chat State
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    timerRef.current = window.setInterval(() => {
      setTimeSeconds(prev => prev + 1);
    }, 1000);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [currentIndex]);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, isChatOpen]);

  const currentQuestion = questions[currentIndex];

  const handleConfirm = () => {
    if (selectedOption === null) return;

    if (timerRef.current) clearInterval(timerRef.current);

    const isCorrect = selectedOption === currentQuestion.correctIndex;
    const newAttempt: AnswerAttempt = {
      questionId: currentQuestion.id,
      selectedIndex: selectedOption,
      timeSpentSeconds: timeSeconds,
      isCorrect
    };

    setAnswers(prev => [...prev, newAttempt]);
    setShowExplanation(true);
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowExplanation(false);
      setTimeSeconds(0);
      // Reset Chat
      setIsChatOpen(false);
      setChatMessages([]);
    } else {
      onComplete(answers);
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsChatLoading(true);

    try {
      // Build simple history string
      const historyText = chatMessages.map(m => `${m.role === 'user' ? 'Aluno' : 'Professor'}: ${m.text}`).join('\n');

      const responseText = await getTutorResponse(
        currentQuestion,
        selectedOption,
        userMsg.text,
        historyText
      );

      setChatMessages(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (error) {
      setChatMessages(prev => [...prev, { role: 'model', text: "Erro ao conectar com o professor. Tente novamente." }]);
    } finally {
      setIsChatLoading(false);
    }
  };

  const isLastQuestion = currentIndex === questions.length - 1;

  return (
    <div className="max-w-3xl mx-auto w-full relative">
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg overflow-hidden transition-colors duration-300">
        {/* Progress Bar */}
        <div className="w-full bg-gray-200 dark:bg-gray-700 h-2">
          <div 
            className="bg-blue-600 dark:bg-blue-500 h-2 transition-all duration-300" 
            style={{ width: `${((currentIndex) / questions.length) * 100}%` }}
          />
        </div>

        <div className="p-6 md:p-8">
          <div className="flex justify-between items-center mb-6">
            <span className="text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wide">
              Questão {currentIndex + 1} de {questions.length}
            </span>
            <div className="flex items-center text-gray-600 dark:text-gray-300 text-sm font-mono bg-gray-100 dark:bg-gray-700 px-3 py-1 rounded-full transition-colors">
              <Clock className="w-4 h-4 mr-2" />
              {Math.floor(timeSeconds / 60)}:{(timeSeconds % 60).toString().padStart(2, '0')}
            </div>
          </div>

          <div className="mb-2">
            <span className="inline-block bg-blue-100 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300 text-xs px-2 py-1 rounded mb-2 font-semibold">
              {currentQuestion.topic}
            </span>
            <h2 className="text-xl md:text-2xl font-bold text-gray-800 dark:text-gray-100 leading-relaxed transition-colors">
              {currentQuestion.text}
            </h2>
          </div>

          <div className="space-y-3 mt-6">
            {currentQuestion.options.map((option, idx) => {
              let optionClass = "border-2 p-4 rounded-lg cursor-pointer transition-all flex items-center ";

              if (showExplanation) {
                if (idx === currentQuestion.correctIndex) {
                  optionClass += "border-green-500 bg-green-50 dark:bg-green-900/30 text-green-900 dark:text-green-300";
                } else if (idx === selectedOption) {
                  optionClass += "border-red-500 bg-red-50 dark:bg-red-900/30 text-red-900 dark:text-red-300";
                } else {
                  optionClass += "border-gray-200 dark:border-gray-700 opacity-50 dark:text-gray-400";
                }
              } else {
                if (selectedOption === idx) {
                  optionClass += "border-blue-500 bg-blue-50 dark:bg-blue-900/30 ring-1 ring-blue-500 text-gray-900 dark:text-white";
                } else {
                  optionClass += "border-gray-200 dark:border-gray-700 hover:border-blue-300 dark:hover:border-blue-500 hover:bg-gray-50 dark:hover:bg-gray-700/50 text-gray-800 dark:text-gray-200";
                }
              }

              return (
                <div 
                  key={idx} 
                  onClick={() => !showExplanation && setSelectedOption(idx)}
                  className={optionClass}
                >
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 flex-shrink-0 ${
                    showExplanation && idx === currentQuestion.correctIndex ? 'border-green-500 bg-green-500 text-white' :
                    showExplanation && idx === selectedOption ? 'border-red-500 bg-red-500 text-white' :
                    selectedOption === idx ? 'border-blue-500 bg-blue-500 text-white' : 'border-gray-300 dark:border-gray-500'
                  }`}>
                    {showExplanation && idx === currentQuestion.correctIndex && <CheckCircle className="w-4 h-4" />}
                    {showExplanation && idx === selectedOption && idx !== currentQuestion.correctIndex && <XCircle className="w-4 h-4" />}
                    {!showExplanation && selectedOption === idx && <div className="w-2 h-2 bg-white rounded-full" />}
                  </div>
                  <span className="text-base">{option}</span>
                </div>
              );
            })}
          </div>

          {showExplanation && (
            <div className="mt-6 space-y-4 animate-fade-in">
              <div className="p-6 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-800 transition-colors">
                <h3 className="font-bold text-blue-900 dark:text-blue-200 mb-3 flex items-center">
                   <div className="bg-blue-200 dark:bg-blue-800 rounded-full p-1 mr-2">
                      <CheckCircle className="w-4 h-4 text-blue-700 dark:text-blue-300" />
                   </div>
                   Explicação do Gabarito:
                </h3>
                <p className="text-blue-900 dark:text-blue-100 text-base leading-relaxed whitespace-pre-wrap font-medium">
                  {currentQuestion.explanation}
                </p>
              </div>

              {/* Tutor Button */}
              <button 
                onClick={() => setIsChatOpen(true)}
                className="w-full py-3 bg-indigo-100 dark:bg-indigo-900/30 hover:bg-indigo-200 dark:hover:bg-indigo-900/50 text-indigo-700 dark:text-indigo-300 rounded-lg flex items-center justify-center font-bold transition-colors border border-indigo-200 dark:border-indigo-700"
              >
                <MessageCircle className="w-5 h-5 mr-2" />
                Não entendi, me ajude! (Falar com Professor IA)
              </button>
            </div>
          )}
        </div>

        <div className="bg-gray-50 dark:bg-gray-900/50 p-6 border-t border-gray-100 dark:border-gray-700 flex justify-end transition-colors">
          {!showExplanation ? (
            <button
              onClick={handleConfirm}
              disabled={selectedOption === null}
              className={`px-8 py-3 rounded-lg font-bold text-white transition-all transform ${
                selectedOption === null 
                  ? 'bg-gray-300 dark:bg-gray-600 cursor-not-allowed' 
                  : 'bg-blue-600 hover:bg-blue-700 hover:-translate-y-1 shadow-md hover:shadow-lg dark:bg-blue-600 dark:hover:bg-blue-500'
              }`}
            >
              Responder
            </button>
          ) : (
            <button
              onClick={handleNext}
              className="px-8 py-3 rounded-lg font-bold text-white bg-green-600 hover:bg-green-700 shadow-md hover:shadow-lg transition-all transform hover:-translate-y-1 dark:bg-green-600 dark:hover:bg-green-500"
            >
              {isLastQuestion ? 'Finalizar Simulado' : 'Próxima Questão'}
            </button>
          )}
        </div>
      </div>

      {/* Tutor Chat Modal */}
      {isChatOpen && (
        <div className="absolute inset-0 z-20 bg-white/95 dark:bg-gray-800/95 backdrop-blur-sm rounded-xl flex flex-col animate-fade-in">
          {/* Chat Header */}
          <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 rounded-t-xl">
             <div className="flex items-center text-indigo-600 dark:text-indigo-400">
               <Bot className="w-6 h-6 mr-2" />
               <h3 className="font-bold">Professor Particular</h3>
             </div>
             <button onClick={() => setIsChatOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
               <X className="w-6 h-6" />
             </button>
          </div>

          {/* Chat Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
            {chatMessages.length === 0 && (
              <div className="text-center text-gray-400 mt-10">
                <p className="text-sm">Olá! Sou seu professor particular.</p>
                <p className="text-xs mt-1">Qual sua dúvida sobre esta questão?</p>
              </div>
            )}
            {chatMessages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] rounded-2xl p-3 text-sm ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-br-none' 
                    : 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded-bl-none border border-gray-200 dark:border-gray-600'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isChatLoading && (
              <div className="flex justify-start">
                 <div className="bg-gray-100 dark:bg-gray-700 rounded-2xl p-3 rounded-bl-none flex space-x-1">
                   <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                   <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                   <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></div>
                 </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Chat Input */}
          <div className="p-4 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 rounded-b-xl">
            <div className="flex space-x-2">
              <input 
                type="text" 
                value={chatInput}
                onChange={(e) => setChatInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Digite sua dúvida..."
                className="flex-1 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 dark:text-white"
              />
              <button 
                onClick={handleSendMessage}
                disabled={isChatLoading || !chatInput.trim()}
                className="bg-indigo-600 hover:bg-indigo-700 text-white rounded-full p-2 disabled:opacity-50 transition-colors"
              >
                <Send className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

