                {errorQuestions.length === 0 ? 'Tudo Limpo!' : 'Revisar Erros Agora'}
              </button>
              {errorQuestions.length === 0 && (
                <p className="text-xs text-center text-green-600 dark:text-green-400 mt-3 font-medium">
                  Parabéns! Você zerou suas pendências.
                </p>
              )}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

