  const [cargo, setCargo] = useState('');
  const [escolaridade, setEscolaridade] = useState<'Fundamental' | 'Médio' | 'Superior'>('Médio');

  const [storedFiles, setStoredFiles] = useState<UploadedFile[]>([]);
  const [errorQuestions, setErrorQuestions] = useState<Question[]>([]);
  const [recentHistory, setRecentHistory] = useState<HistoryItem[]>([]);
  const [context, setContext] = useState('');
  const [streak, setStreak] = useState(0);

  useEffect(() => {
    loadData();
    calculateStreak();
  }, []);

  const loadData = async () => {
    try {
      const files = await getFiles();
      setStoredFiles(files);
      const errors = await getErrorQuestions();
      setErrorQuestions(errors);
      const hist = await getHistory();
      setRecentHistory(hist.reverse().slice(0, 5));
    } catch (error) {
      console.error("Failed to load data", error);
    }
  };

  const calculateStreak = () => {
    const lastStudy = localStorage.getItem('lastStudyDate');
    const currentStreak = parseInt(localStorage.getItem('studyStreak') || '0', 10);

    if (lastStudy) {
      const lastDate = new Date(parseInt(lastStudy));
      const today = new Date();
      lastDate.setHours(0,0,0,0);
      today.setHours(0,0,0,0);

      const diffTime = Math.abs(today.getTime() - lastDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays <= 1) {
        setStreak(currentStreak);
      } else {
        setStreak(0);
        localStorage.setItem('studyStreak', '0');
      }
    } else {
      setStreak(0);
    }
  };

  const updateStreakOnStart = () => {
    const lastStudy = localStorage.getItem('lastStudyDate');
    const today = new Date();
    today.setHours(0,0,0,0);

    let newStreak = parseInt(localStorage.getItem('studyStreak') || '0', 10);

    if (lastStudy) {
      const lastDate = new Date(parseInt(lastStudy));
      lastDate.setHours(0,0,0,0);
      const diffTime = Math.abs(today.getTime() - lastDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays === 1) {
        newStreak += 1;
      } else if (diffDays > 1) {
        newStreak = 1; 
      }
    } else {
      newStreak = 1; 
    }

    localStorage.setItem('lastStudyDate', Date.now().toString());
    localStorage.setItem('studyStreak', newStreak.toString());
    setStreak(newStreak);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        if (file.type === 'application/pdf' || file.type === 'text/plain') {
          const reader = new FileReader();
          const filePromise = new Promise<UploadedFile>((resolve) => {
            reader.onload = (event) => {
              const base64 = (event.target?.result as string).split(',')[1];
              resolve({ name: file.name, mimeType: file.type, data: base64 });
            };
          });
          const pFile = await filePromise;
          await saveFile(pFile);
        }
      }
      loadData();
    }
  };

  const handleRemoveFile = async (id: string) => {
    if(!id) return;
    await deleteFile(id);
    loadData();
  };

  const handleStartWrapper = () => {
    if (!banca.trim() || !cargo.trim()) {
      alert("Por favor, preencha a Banca e o Cargo para iniciar.");
      return;
    }
    updateStreakOnStart();
    const profile: ExamProfile = { banca, cargo, escolaridade };
    onStart(profile, storedFiles, context);
  };

  const handleReviewWrapper = () => {
    updateStreakOnStart();
    onStartReview(errorQuestions);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-10">

      {/* Header */}
      <div className="flex flex-col md:flex-row items-center justify-between mb-8">
         <div className="flex items-center space-x-4 mb-4 md:mb-0">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-2xl shadow-lg transform rotate-3 hover:rotate-0 transition-transform duration-300">
              <BookOpen className="w-8 h-8 text-white" />
            </div>
            <div>
               <h2 className="text-3xl font-extrabold text-gray-800 dark:text-white tracking-tight">CogniQuest.IA</h2>
               <p className="text-sm text-gray-500 dark:text-gray-400">Preparatório Universal para Concursos</p>
            </div>
         </div>

         {/* Streak */}
         <div className="bg-orange-100 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-700/50 px-5 py-3 rounded-2xl flex items-center shadow-sm">
            <div className={`p-2 rounded-full mr-3 ${streak > 0 ? 'bg-orange-500 text-white animate-pulse' : 'bg-gray-300 dark:bg-gray-700 text-gray-500'}`}>
              <Flame className="w-5 h-5" />
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400 font-bold uppercase tracking-wider">Ofensiva</p>
              <p className="text-xl font-bold text-gray-800 dark:text-white">{streak} dias</p>
            </div>
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

        {/* Main Form (Left 2/3) */}
        <div className="md:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-100 dark:border-gray-700 transition-colors">
          <div className="flex items-center space-x-2 mb-6">
            <Play className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
            <h3 className="text-xl font-bold text-gray-800 dark:text-white">Configurar Simulado</h3>
          </div>

          <div className="space-y-6">

            {/* Input Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center">
                  <Building2 className="w-4 h-4 mr-1 text-indigo-500" /> Banca Organizadora
                </label>
                <input 
                  type="text" 
                  value={banca}
                  onChange={(e) => setBanca(e.target.value)}
                  placeholder="Ex: Cebraspe, Vunesp, FGV..."
                  className="w-full p-3 bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-600 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-gray-800 dark:text-white transition-all"
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center">
