import React, { useState, useEffect } from 'react';
import { AppView, Question, AnswerAttempt, UploadedFile, ExamProfile, StrategicAnalysis, HistoryItem } from './types';
import UploadSection from './components/UploadSection';
import QuizInterface from './components/QuizInterface';
import ResultsView from './components/ResultsView';
import { generateQuestions, analyzePerformanceAndPattern } from './services/geminiService';
import { GraduationCap, Moon, Sun } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [loading, setLoading] = useState(false);

  // profile state replaces role
  const [profile, setProfile] = useState<ExamProfile>({
    banca: '',
    cargo: '',
    escolaridade: 'Médio'
  });

  const [questions, setQuestions] = useState<Question[]>([]);
  const [answers, setAnswers] = useState<AnswerAttempt[]>([]);
  const [analysis, setAnalysis] = useState<StrategicAnalysis | null>(null);

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return true;
    }
    return false;
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
  };

  const handleStartQuiz = async (selectedProfile: ExamProfile, files: UploadedFile[], context: string) => {
    setLoading(true);
    setProfile(selectedProfile);
    try {
      const generatedQuestions = await generateQuestions(selectedProfile, files, context);
      if (generatedQuestions.length > 0) {
        setQuestions(generatedQuestions);
        setAnswers([]); 
        setAnalysis(null);
        setView(AppView.QUIZ);
      } else {
        alert("A IA não conseguiu gerar questões para este perfil. Tente reformular a Banca ou Cargo.");
      }
    } catch (error) {
      console.error(error);
      alert("Erro ao conectar com a IA.");
    } finally {
      setLoading(false);
    }
  };

  const handleStartReview = (errorQuestions: Question[]) => {
    const shuffled = [...errorQuestions].sort(() => Math.random() - 0.5);
    setQuestions(shuffled);
    setAnswers([]);
    setAnalysis(null);
    setView(AppView.QUIZ);
  };

  const handleViewHistory = (item: HistoryItem) => {
    if (item.questions && item.answers) {
      setQuestions(item.questions);
      setAnswers(item.answers);
      setAnalysis(item.analysis);
      if (item.profile) {
        setProfile(item.profile);
      }
      setView(AppView.RESULTS);
    } else {
      alert("Item de histórico inválido ou antigo.");
    }
  };

  const handleQuizComplete = async (completedAnswers: AnswerAttempt[]) => {
    setAnswers(completedAnswers);
    setView(AppView.RESULTS);

    analyzePerformanceAndPattern(profile, completedAnswers, questions).then(result => {
      setAnalysis(result);
    });
  };

  const handleRestart = () => {
    setQuestions([]);
    setAnswers([]);
    setAnalysis(null);
    setView(AppView.HOME);
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex flex-col font-sans text-gray-800 dark:text-gray-100 transition-colors duration-300">

      {/* Header */}
      <header className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 sticky top-0 z-10 transition-colors duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={handleRestart}>
            <div className="bg-gradient-to-tr from-indigo-600 to-purple-600 p-2 rounded-lg">
              <GraduationCap className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-700 to-purple-700 dark:from-indigo-400 dark:to-purple-400">
                CogniQuest.IA
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button
              onClick={toggleTheme}
              className="p-2 rounded-full text-gray-500 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-700 transition-colors"
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            {view !== AppView.HOME && (
              <button 
                onClick={handleRestart}
                className="text-sm font-medium text-gray-500 hover:text-indigo-600 dark:text-gray-400 dark:hover:text-indigo-400 transition-colors"
              >
                Voltar ao Início
              </button>
            )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow p-4 md:p-8">
        {view === AppView.HOME && (
          <UploadSection 
            onStart={handleStartQuiz} 
            onStartReview={handleStartReview}
            onViewHistory={handleViewHistory}
            isLoading={loading} 
          />
        )}

        {view === AppView.QUIZ && (
          <QuizInterface 
            questions={questions} 
            onComplete={handleQuizComplete} 
          />
        )}

        {view === AppView.RESULTS && (
          <ResultsView 
            answers={answers} 
            questions={questions} 
            analysis={analysis} 
            profile={profile}
            onRestart={handleRestart}
          />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 py-6 mt-auto transition-colors duration-300">
        <div className="max-w-7xl mx-auto px-4 text-center text-gray-400 dark:text-gray-500 text-sm">
          <p>© {new Date().getFullYear()} CogniQuest.IA. Sistema Inteligente Multi-Banca.</p>
          <p className="mt-1 text-xs">Desenvolvido por Marcos Felipe</p>
        </div>
      </footer>

    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { AnswerAttempt, Question, StrategicAnalysis, ExamProfile, HistoryItem } from '../types';
import { saveHistory, getHistory, saveErrorQuestion, removeErrorQuestion } from '../services/storageService';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend, LineChart, Line, AreaChart, Area } from 'recharts';
import { AlertTriangle, Award, BookOpen, Clock, Target, TrendingUp, Layers, Hourglass, Calendar } from 'lucide-react';

interface ResultsViewProps {
  answers: AnswerAttempt[];
  questions: Question[];
  analysis: StrategicAnalysis | null;
  profile: ExamProfile;
  onRestart: () => void;
}

const COLORS = {
  correct: '#10B981',
  incorrect: '#EF4444',
};

const ResultsView: React.FC<ResultsViewProps> = ({ answers, questions, analysis, profile, onRestart }) => {
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [savedErrorsCount, setSavedErrorsCount] = useState(0);

  const correctCount = answers.filter(a => a.isCorrect).length;
  const incorrectCount = answers.length - correctCount;
  const totalTimeSeconds = answers.reduce((acc, curr) => acc + curr.timeSpentSeconds, 0);
  const avgTime = Math.round(totalTimeSeconds / answers.length);

  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    if (h > 0) return `${h}h ${m}m`;
    if (m > 0) return `${m}m ${s}s`;
    return `${s}s`;
  };

  const topicData = React.useMemo(() => {
    const topics: Record<string, { total: number; correct: number }> = {};
    questions.forEach((q) => {
      const t = q.topic || 'Geral';
      if (!topics[t]) topics[t] = { total: 0, correct: 0 };
      topics[t].total++;
      if (answers.find(a => a.questionId === q.id)?.isCorrect) {
        topics[t].correct++;
      }
    });
    return Object.entries(topics).map(([name, data]) => ({
      name,
      Acertos: data.correct,
      Erros: data.total - data.correct,
      total: data.total,
      percentage: Math.round((data.correct / data.total) * 100)
    })).sort((a, b) => b.percentage - a.percentage);
  }, [questions, answers]);

  useEffect(() => {
    const processResults = async () => {
      const currentHistory = await getHistory();

      const isDuplicate = currentHistory.length > 0 && 
                          currentHistory[currentHistory.length - 1].score === Math.round((correctCount / answers.length) * 100) &&
                          currentHistory[currentHistory.length - 1].totalQuestions === answers.length &&
                          Math.abs(currentHistory[currentHistory.length - 1].date - Date.now()) < 5000;

      if (analysis && !isDuplicate) {
        const item: Omit<HistoryItem, 'id'> = {
          date: Date.now(),
          profile: profile,
          score: Math.round((correctCount / answers.length) * 100),
          totalQuestions: answers.length,
          totalTimeSeconds: totalTimeSeconds, 
          analysis,
          questions,
          answers
        };
        await saveHistory(item);

        const h = await getHistory();
        setHistory(h);

        let errorsSaved = 0;
        for (const answer of answers) {
          if (!answer.isCorrect) {
            const question = questions.find(q => q.id === answer.questionId);
            if (question) {
              await saveErrorQuestion(question);
              errorsSaved++;
            }
          } else {
            await removeErrorQuestion(answer.questionId);
          }
        }
        setSavedErrorsCount(errorsSaved);
      } else {
        setHistory(currentHistory);
      }
    };

    processResults();
  }, [analysis, correctCount, answers, questions, profile, totalTimeSeconds]);

  const pieData = [
    { name: 'Corretas', value: correctCount },
    { name: 'Erradas', value: incorrectCount },
  ];

  const historyData = history.map(h => ({
    date: new Date(h.date).toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit'}),
    nota: h.score,
    minutos: Math.round((h.totalTimeSeconds || 0) / 60)
  }));

  const totalLifetimeSeconds = history.reduce((acc, curr) => acc + (curr.totalTimeSeconds || 0), 0);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-gray-800 p-3 border border-gray-200 dark:border-gray-700 shadow-lg rounded-lg">
          <p className="font-bold text-gray-700 dark:text-gray-200">{label}</p>
          {payload.map((p: any, idx: number) => (
             <p key={idx} style={{ color: p.color }} className="text-sm">
                {p.name}: {p.value} {p.unit || ''}
             </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="w-full max-w-7xl mx-auto space-y-8 animate-fade-in-up pb-12">

      {savedErrorsCount > 0 && (
        <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-700 p-4 rounded-xl flex items-center justify-between">
          <div className="flex items-center">
            <AlertTriangle className="w-6 h-6 text-amber-600 dark:text-amber-400 mr-3" />
            <div>
              <h4 className="font-bold text-amber-800 dark:text-amber-200">Atenção aos Detalhes</h4>
              <p className="text-sm text-amber-700 dark:text-amber-300">
                {savedErrorsCount} erros foram salvos para revisão.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Profile Header in Results */}
      <div className="text-center mb-4">
        <h2 className="text-xl font-bold text-gray-800 dark:text-white">Resultado: {profile.cargo}</h2>
        <p className="text-sm text-gray-500">{profile.banca} - Nível {profile.escolaridade}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {/* Score Card */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 relative overflow-hidden group">
          <div className="absolute right-0 top-0 w-24 h-24 bg-blue-500/10 rounded-bl-full -mr-4 -mt-4 transition-transform group-hover:scale-110"></div>
          <p className="text-gray-500 dark:text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Nota Final</p>
          <div className="flex items-end space-x-2">
            <h3 className="text-4xl font-extrabold text-gray-800 dark:text-white">{Math.round((correctCount / answers.length) * 100)}%</h3>
            <span className="text-sm text-gray-400 mb-1">aproveitamento</span>
          </div>
          <Award className="absolute right-6 top-6 w-8 h-8 text-blue-500 opacity-50" />
        </div>

        {/* Correct/Total Card */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 relative overflow-hidden group">
          <div className="absolute right-0 top-0 w-24 h-24 bg-green-500/10 rounded-bl-full -mr-4 -mt-4 transition-transform group-hover:scale-110"></div>
          <p className="text-gray-500 dark:text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Acertos</p>
          <div className="flex items-end space-x-2">
            <h3 className="text-4xl font-extrabold text-green-600 dark:text-green-400">{correctCount}</h3>
            <span className="text-sm text-gray-400 mb-1">de {answers.length} questões</span>
          </div>
          <Target className="absolute right-6 top-6 w-8 h-8 text-green-500 opacity-50" />
        </div>

        {/* Time Card */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 relative overflow-hidden group">
           <div className="absolute right-0 top-0 w-24 h-24 bg-purple-500/10 rounded-bl-full -mr-4 -mt-4 transition-transform group-hover:scale-110"></div>
          <p className="text-gray-500 dark:text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Tempo do Simulado</p>
          <div className="flex items-end space-x-2">
            <h3 className="text-4xl font-extrabold text-gray-800 dark:text-white">{formatDuration(totalTimeSeconds)}</h3>
          </div>
          <p className="text-xs text-gray-400 mt-1">Média: {avgTime}s / questão</p>
          <Clock className="absolute right-6 top-6 w-8 h-8 text-purple-500 opacity-50" />
        </div>

        {/* Action Card */}
        <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-6 rounded-2xl shadow-lg flex flex-col justify-center items-center text-center">
             <h4 className="text-white font-bold mb-3 text-sm">Pronto para o próximo?</h4>
             <button onClick={onRestart} className="w-full bg-white text-indigo-700 hover:bg-indigo-50 font-bold py-3 px-4 rounded-xl shadow-md transition-all transform hover:-translate-y-0.5">
                Voltar ao Início
             </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Charts */}
        <div className="lg:col-span-2 space-y-8">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
             {/* Donut Chart */}
             <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
               <h3 className="text-lg font-bold text-gray-700 dark:text-gray-200 mb-4 text-center">Resumo</h3>
               <div className="h-64 w-full relative">
                 <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={pieData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                      stroke="none"
                    >
                      <Cell key="cell-correct" fill={COLORS.correct} />
                      <Cell key="cell-incorrect" fill={COLORS.incorrect} />
                    </Pie>
                    <Tooltip content={<CustomTooltip />} />
                    <Legend verticalAlign="bottom" height={36} iconType="circle"/>
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <div className="text-center">
                    <span className="block text-3xl font-bold text-gray-800 dark:text-white">{Math.round((correctCount / answers.length) * 100)}%</span>
                  </div>
                </div>
               </div>
             </div>

             {/* Topic Performance */}
             <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                <h3 className="text-lg font-bold text-gray-700 dark:text-gray-200 mb-4 flex items-center justify-center">
                  <Layers className="w-5 h-5 mr-2 text-indigo-500" />
                  Matérias
                </h3>
                <div className="h-64 w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart
                      layout="vertical"
                      data={topicData}
                      margin={{ top: 5, right: 30, left: 40, bottom: 5 }}
                    >
                      <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#374151" opacity={0.2} />
                      <XAxis type="number" hide />
                      <YAxis 
                        dataKey="name" 
                        type="category" 
                        width={100} 
                        tick={{ fill: '#6B7280', fontSize: 11 }} 
                        interval={0}
                      />
                      <Tooltip content={<CustomTooltip />} cursor={{fill: 'transparent'}} />
                      <Bar dataKey="Acertos" stackId="a" fill={COLORS.correct} radius={[0, 4, 4, 0]} barSize={20} />
                      <Bar dataKey="Erros" stackId="a" fill="#E5E7EB" radius={[0, 4, 4, 0]} barSize={20} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
             </div>
          </div>

          {/* History */}
          {history.length > 0 && (
            <div className="space-y-6">
              <div className="bg-gradient-to-r from-purple-600 to-indigo-600 rounded-2xl p-6 text-white shadow-lg flex items-center justify-between">
                <div>
                  <h3 className="text-lg font-semibold opacity-90">Total de Horas</h3>
                </div>
                <div className="text-right">
                  <div className="text-4xl font-bold flex items-center gap-2">
                    <Hourglass className="w-8 h-8 opacity-80" />
                    {formatDuration(totalLifetimeSeconds)}
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                  <h3 className="text-lg font-bold text-gray-700 dark:text-gray-200 mb-6 flex items-center">
                    <TrendingUp className="w-5 h-5 mr-2 text-blue-500" />
                    Evolução
                  </h3>
                  <div className="h-60 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={historyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#374151" opacity={0.1} vertical={false} />
                        <XAxis dataKey="date" stroke="#9CA3AF" tick={{fontSize: 10}} tickLine={false} axisLine={false} dy={10} />
                        <YAxis domain={[0, 100]} stroke="#9CA3AF" tickLine={false} axisLine={false} />
                        <Tooltip content={<CustomTooltip />} />
                        <Line 
                          type="monotone" 
                          dataKey="nota" 
                          stroke="#3B82F6" 
                          strokeWidth={3} 
                          dot={{r: 4, fill: '#3B82F6', strokeWidth: 2, stroke: '#fff'}} 
                        />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                  <h3 className="text-lg font-bold text-gray-700 dark:text-gray-200 mb-6 flex items-center">
                    <Calendar className="w-5 h-5 mr-2 text-purple-500" />
                    Tempo (min)
                  </h3>
                  <div className="h-60 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={historyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                        <defs>
                          <linearGradient id="colorTime" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#8B5CF6" stopOpacity={0.3}/>
                            <stop offset="95%" stopColor="#8B5CF6" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="#374151" opacity={0.1} vertical={false} />
                        <XAxis dataKey="date" stroke="#9CA3AF" tick={{fontSize: 10}} tickLine={false} axisLine={false} dy={10} />
                        <YAxis stroke="#9CA3AF" tickLine={false} axisLine={false} />
                        <Tooltip content={<CustomTooltip />} />
                        <Area 
                          type="monotone" 
                          dataKey="minutos" 
                          stroke="#8B5CF6" 
                          fillOpacity={1} 
                          fill="url(#colorTime)" 
                        />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Right Column: Analysis */}
        <div className="lg:col-span-1">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-lg border border-gray-100 dark:border-gray-700 h-full flex flex-col">
            <h3 className="text-xl font-bold text-gray-800 dark:text-white mb-6 flex items-center border-b border-gray-100 dark:border-gray-700 pb-4">
              <BookOpen className="w-6 h-6 mr-2 text-blue-600 dark:text-blue-400" />
              Análise Estratégica
            </h3>

            {analysis ? (
              <div className="space-y-6 overflow-y-auto flex-1 custom-scrollbar pr-2">
                <div className="bg-amber-50 dark:bg-amber-900/10 p-4 rounded-xl border border-amber-200 dark:border-amber-700/30">
                  <h4 className="font-bold text-amber-800 dark:text-amber-200 flex items-center mb-3 text-sm uppercase tracking-wide">
                    <AlertTriangle className="w-4 h-4 mr-2" />
                    Padrão {profile.banca}
                  </h4>
                  <p className="text-sm text-amber-900 dark:text-amber-100 leading-relaxed whitespace-pre-wrap">
                    {analysis.bancaPattern}
                  </p>
                </div>

                <div className="bg-indigo-50 dark:bg-indigo-900/10 p-4 rounded-xl border border-indigo-200 dark:border-indigo-700/30">
                  <h4 className="font-bold text-indigo-800 dark:text-indigo-200 mb-3 text-sm uppercase tracking-wide">
                    Plano de Estudo
                  </h4>
                  <p className="text-sm text-indigo-900 dark:text-indigo-100 leading-relaxed whitespace-pre-wrap">
                    {analysis.recommendations}
                  </p>
                </div>

                <div className="grid grid-cols-1 gap-4">
                   <div>
                    <h4 className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-2">Pontos Fortes</h4>
                    <div className="flex flex-wrap gap-2">
                      {analysis.strengths.length > 0 ? analysis.strengths.map((s, i) => (
                        <span key={i} className="px-3 py-1 bg-green-100 dark:bg-green-900/20 text-green-700 dark:text-green-300 rounded-full text-xs font-semibold border border-green-200 dark:border-green-800">
                          {s}
                        </span>
                      )) : <span className="text-sm text-gray-400 italic">Continue estudando para descobrir.</span>}
                    </div>
                   </div>

                   <div>
                    <h4 className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-2">Atenção (Pontos Fracos)</h4>
                    <div className="flex flex-wrap gap-2">
                      {analysis.weaknesses.length > 0 ? analysis.weaknesses.map((w, i) => (
                        <span key={i} className="px-3 py-1 bg-red-100 dark:bg-red-900/20 text-red-700 dark:text-red-300 rounded-full text-xs font-semibold border border-red-200 dark:border-red-800">
                          {w}
                        </span>
                      )) : <span className="text-sm text-gray-400 italic">Nenhum ponto crítico detectado.</span>}
                    </div>
                   </div>
                </div>

              </div>
            ) : (
               <div className="flex-1 flex flex-col items-center justify-center text-gray-400 dark:text-gray-500 space-y-6 min-h-[300px]">
                 <div className="relative">
                   <div className="w-16 h-16 border-4 border-blue-100 dark:border-gray-700 rounded-full"></div>
                   <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin absolute top-0 left-0"></div>
                 </div>
                 <div className="text-center space-y-2">
                   <p className="font-medium text-gray-600 dark:text-gray-300">Consultando a IA...</p>
                   <p className="text-xs max-w-[200px] mx-auto">Analisando o padrão da banca {profile.banca}...</p>
                 </div>
               </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ResultsView;

{
  "name": "CogniQuest.IA - Preparatório Universal",
  "description": "Sistema inteligente CogniQuest.IA de estudo universal para concursos. Simula qualquer banca e cargo (Cebraspe, Vunesp, FGV, etc) com geração de questões via IA e análise de desempenho.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useMemo } from 'react';
import { UploadedFile, ExamProfile, Question, HistoryItem, StrategicAnalysis } from '../types';
import { saveFile, getFiles, deleteFile, getErrorQuestions, getHistory } from '../services/storageService';
import { UploadCloud, FileText, Trash2, BookOpen, BrainCircuit, Play, Flame, History, Building2, Briefcase, GraduationCap, Trophy, Target, Clock, TrendingUp, Lightbulb } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, CartesianGrid } from 'recharts';

interface UploadSectionProps {
  onStart: (profile: ExamProfile, files: UploadedFile[], context: string) => void;
  onStartReview: (questions: Question[]) => void;
  onViewHistory: (item: HistoryItem) => void;
  isLoading: boolean;
}

const COLORS = {
  high: '#10B981', // Green
  mid: '#F59E0B',  // Amber
  low: '#EF4444',  // Red
};

const UploadSection: React.FC<UploadSectionProps> = ({ onStart, onStartReview, onViewHistory, isLoading }) => {
  // State for Dynamic Inputs
  const [banca, setBanca] = useState('');
  const [cargo, setCargo] = useState('');
  const [escolaridade, setEscolaridade] = useState<'Fundamental' | 'Médio' | 'Superior'>('Médio');

  const [storedFiles, setStoredFiles] = useState<UploadedFile[]>([]);
  const [errorQuestions, setErrorQuestions] = useState<Question[]>([]);
  const [recentHistory, setRecentHistory] = useState<HistoryItem[]>([]);
  const [allHistory, setAllHistory] = useState<HistoryItem[]>([]); // For stats
  const [context, setContext] = useState('');
  const [streak, setStreak] = useState(0);

  // Load everything on mount
  useEffect(() => {
    loadData();
    calculateStreak();
    loadPreferences();
  }, []);

  const loadPreferences = () => {
    const saved = localStorage.getItem('lastExamProfile');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.banca) setBanca(parsed.banca);
        if (parsed.cargo) setCargo(parsed.cargo);
        if (parsed.escolaridade) setEscolaridade(parsed.escolaridade);
      } catch (e) {
        console.error("Failed to load preferences", e);
      }
    }
  };

  const savePreferences = () => {
    const profile = { banca, cargo, escolaridade };
    localStorage.setItem('lastExamProfile', JSON.stringify(profile));
  };

  const loadData = async () => {
    try {
      const files = await getFiles();
      setStoredFiles(files);
      const errors = await getErrorQuestions();
      setErrorQuestions(errors);
      const hist = await getHistory();
      setAllHistory(hist);
      setRecentHistory([...hist].reverse().slice(0, 5));
    } catch (error) {
      console.error("Failed to load data", error);
    }
  };

  const calculateStreak = () => {
    const lastStudy = localStorage.getItem('lastStudyDate');
    const currentStreak = parseInt(localStorage.getItem('studyStreak') || '0', 10);

    if (lastStudy) {
      const lastDate = new Date(parseInt(lastStudy));
      const today = new Date();
      lastDate.setHours(0,0,0,0);
      today.setHours(0,0,0,0);

      const diffTime = Math.abs(today.getTime() - lastDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays <= 1) {
        setStreak(currentStreak);
      } else {
        setStreak(0);
        localStorage.setItem('studyStreak', '0');
      }
    } else {
      setStreak(0);
    }
  };

  const updateStreakOnStart = () => {
    const lastStudy = localStorage.getItem('lastStudyDate');
    const today = new Date();
    today.setHours(0,0,0,0);

    let newStreak = parseInt(localStorage.getItem('studyStreak') || '0', 10);

    if (lastStudy) {
      const lastDate = new Date(parseInt(lastStudy));
      lastDate.setHours(0,0,0,0);
      const diffTime = Math.abs(today.getTime() - lastDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays === 1) {
        newStreak += 1;
      } else if (diffDays > 1) {
        newStreak = 1; 
      }
    } else {
      newStreak = 1; 
    }

    localStorage.setItem('lastStudyDate', Date.now().toString());
    localStorage.setItem('studyStreak', newStreak.toString());
    setStreak(newStreak);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        if (file.type === 'application/pdf' || file.type === 'text/plain') {
          const reader = new FileReader();
          const filePromise = new Promise<UploadedFile>((resolve) => {
            reader.onload = (event) => {
              const base64 = (event.target?.result as string).split(',')[1];
              resolve({ name: file.name, mimeType: file.type, data: base64 });
            };
          });
          const pFile = await filePromise;
          await saveFile(pFile);
        }
      }
      loadData();
    }
  };

  const handleRemoveFile = async (id: string) => {
    if(!id) return;
    await deleteFile(id);
    loadData();
  };

  const handleStartWrapper = () => {
    if (!banca.trim() || !cargo.trim()) {
      alert("Por favor, preencha a Banca e o Cargo para iniciar.");
      return;
    }
    savePreferences(); // Auto-save
    updateStreakOnStart();
    const profile: ExamProfile = { banca, cargo, escolaridade };
    onStart(profile, storedFiles, context);
  };

  const handleReviewWrapper = () => {
    updateStreakOnStart();
    onStartReview(errorQuestions);
  };

  // --- DASHBOARD CALCULATIONS ---
  const stats = useMemo(() => {
    if (allHistory.length === 0) return null;

    let totalSeconds = 0;
    let totalQuestionsAnswered = 0;
    let totalCorrect = 0;
    const topicStats: Record<string, { correct: number; total: number }> = {};

    allHistory.forEach(h => {
      totalSeconds += h.totalTimeSeconds || 0;
      totalQuestionsAnswered += h.totalQuestions || 0;
      // Estimate correct based on score if answers not present (legacy) or calculate exactly
      const correctInSession = Math.round((h.score / 100) * h.totalQuestions);
      totalCorrect += correctInSession;

      // Aggregating topics
      if (h.questions && h.answers) {
        h.questions.forEach(q => {
          const t = q.topic || 'Geral';
          if (!topicStats[t]) topicStats[t] = { correct: 0, total: 0 };
          topicStats[t].total++;
          const isCorrect = h.answers?.find(a => a.questionId === q.id)?.isCorrect;
          if (isCorrect) topicStats[t].correct++;
        });
      }
    });

    // Calculate Weaknesses and Strengths based on data
    const topicPerformance = Object.entries(topicStats).map(([topic, data]) => ({
      topic,
      percentage: Math.round((data.correct / data.total) * 100),
      total: data.total
    })).sort((a, b) => a.percentage - b.percentage); // Lowest first

    const globalScore = totalQuestionsAnswered > 0 ? Math.round((totalCorrect / totalQuestionsAnswered) * 100) : 0;

    // Get latest recommendations
    const lastSession = allHistory[allHistory.length - 1];
    const latestPlan = lastSession?.analysis?.recommendations || "Realize um simulado para gerar seu plano.";

    return {
      totalHours: Math.floor(totalSeconds / 3600),
      totalMinutes: Math.floor((totalSeconds % 3600) / 60),
      globalScore,
      questionsCount: totalQuestionsAnswered,
      topicPerformance, // Full list for chart
      latestPlan
    };
  }, [allHistory]);

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in pb-10">

      {/* Header & Streak */}
      <div className="flex flex-col md:flex-row items-center justify-between">
         <div className="flex items-center space-x-4 mb-4 md:mb-0">
            <div className="inline-flex items-center justify-center w-14 h-14 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-2xl shadow-lg">
              <BookOpen className="w-7 h-7 text-white" />
            </div>
            <div>
               <h2 className="text-2xl font-extrabold text-gray-800 dark:text-white tracking-tight">Painel do Estudante</h2>
               <p className="text-sm text-gray-500 dark:text-gray-400">Bem-vindo de volta!</p>
            </div>
         </div>

         <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 px-5 py-2 rounded-2xl flex items-center shadow-sm">
            <div className={`p-2 rounded-full mr-3 ${streak > 0 ? 'bg-orange-100 text-orange-600' : 'bg-gray-100 text-gray-400'}`}>
              <Flame className="w-5 h-5" />
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400 font-bold uppercase tracking-wider">Ofensiva</p>
              <p className="text-lg font-bold text-gray-800 dark:text-white">{streak} dias</p>
            </div>
         </div>
      </div>

      {/* --- DASHBOARD SECTION --- */}
      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 animate-fade-in-up">

          {/* Stats Cards */}
          <div className="md:col-span-4 grid grid-cols-1 sm:grid-cols-3 gap-6">
            <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm flex items-center">
              <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-xl mr-4 text-blue-600 dark:text-blue-400">
                <Clock className="w-6 h-6" />
              </div>
              <div>
                <p className="text-xs text-gray-500 uppercase font-bold">Tempo Total</p>
                <h3 className="text-2xl font-bold text-gray-800 dark:text-white">
                  {stats.totalHours}h {stats.totalMinutes}m
                </h3>
              </div>
            </div>

            <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm flex items-center">
              <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-xl mr-4 text-green-600 dark:text-green-400">
                <Target className="w-6 h-6" />
              </div>
              <div>
                <p className="text-xs text-gray-500 uppercase font-bold">Precisão Global</p>
                <h3 className="text-2xl font-bold text-gray-800 dark:text-white">{stats.globalScore}%</h3>
              </div>
            </div>

            <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm flex items-center">
              <div className="p-3 bg-purple-50 dark:bg-purple-900/20 rounded-xl mr-4 text-purple-600 dark:text-purple-400">
                <Trophy className="w-6 h-6" />
              </div>
              <div>
                <p className="text-xs text-gray-500 uppercase font-bold">Questões Feitas</p>
                <h3 className="text-2xl font-bold text-gray-800 dark:text-white">{stats.questionsCount}</h3>
              </div>
            </div>
          </div>

          {/* Charts & Plans */}
          <div className="md:col-span-2 bg-white dark:bg-gray-800 p-6 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm">
             <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 flex items-center">
               <TrendingUp className="w-5 h-5 mr-2 text-indigo-500" />
               Pontos Fortes e Fracos (Geral)
             </h3>
             <div className="h-64">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={stats.topicPerformance} layout="vertical" margin={{top: 5, right: 30, left: 40, bottom: 5}}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#374151" opacity={0.1} />
                    <XAxis type="number" domain={[0, 100]} hide />
                    <YAxis dataKey="topic" type="category" width={100} tick={{fontSize: 10}} interval={0} />
                    <Tooltip 
                      contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'}}
                      cursor={{fill: 'transparent'}}
                    />
                    <Bar dataKey="percentage" radius={[0, 4, 4, 0]} barSize={20}>
                      {stats.topicPerformance.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.percentage >= 70 ? COLORS.high : entry.percentage >= 50 ? COLORS.mid : COLORS.low} />
                      ))}
                    </Bar>
                 </BarChart>
               </ResponsiveContainer>
             </div>
             <p className="text-xs text-center text-gray-400 mt-2">Baseado em todo o seu histórico.</p>
          </div>

          <div className="md:col-span-2 bg-gradient-to-br from-indigo-50 to-white dark:from-gray-800 dark:to-gray-800 p-6 rounded-2xl border border-indigo-100 dark:border-gray-700 shadow-sm flex flex-col">
             <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 flex items-center">
               <Lightbulb className="w-5 h-5 mr-2 text-amber-500" />
               Plano de Estudo Atual
             </h3>
             <div className="flex-1 overflow-y-auto custom-scrollbar max-h-60 pr-2">
               <p className="text-sm text-gray-700 dark:text-gray-300 leading-relaxed whitespace-pre-wrap">
                 {stats.latestPlan}
               </p>
             </div>
             <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
               <p className="text-xs text-gray-500 italic">
                 Dica: Faça um novo simulado para atualizar este plano com base no seu desempenho mais recente.
               </p>
             </div>
          </div>

        </div>
      )}

      {/* --- CONFIG SECTION (FORM) --- */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

        {/* Main Form */}
        <div className="md:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-100 dark:border-gray-700 transition-colors relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>

          <div className="flex items-center space-x-2 mb-6">
            <Play className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
            <h3 className="text-xl font-bold text-gray-800 dark:text-white">Iniciar Novo Simulado</h3>
          </div>

          <div className="space-y-6">

            {/* Input Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center">
                  <Building2 className="w-4 h-4 mr-1 text-indigo-500" /> Banca Organizadora
                </label>
                <input 
                  type="text" 
                  value={banca}
                  onChange={(e) => setBanca(e.target.value)}
                  placeholder="Ex: Cebraspe, Vunesp, FGV..."
                  className="w-full p-3 bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-600 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-gray-800 dark:text-white transition-all font-semibold"
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center">
                  <Briefcase className="w-4 h-4 mr-1 text-indigo-500" /> Cargo Pretendido
                </label>
                <input 
                  type="text" 
                  value={cargo}
                  onChange={(e) => setCargo(e.target.value)}
                  placeholder="Ex: Policial, Técnico Adm..."
                  className="w-full p-3 bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-600 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-gray-800 dark:text-white transition-all font-semibold"
                />
              </div>

              <div className="space-y-2 md:col-span-2">
                 <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center">
                  <GraduationCap className="w-4 h-4 mr-1 text-indigo-500" /> Nível de Escolaridade
                </label>
                <div className="flex gap-2">
                  {(['Fundamental', 'Médio', 'Superior'] as const).map((nivel) => (
                    <button
                      key={nivel}
                      onClick={() => setEscolaridade(nivel)}
                      className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all border ${
                        escolaridade === nivel 
                          ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' 
                          : 'bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-300 border-gray-300 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-600'
                      }`}
                    >
                      {nivel}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* File Upload */}
            <div className="relative pt-4 border-t border-gray-100 dark:border-gray-700">
              <label className="flex justify-between items-center text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                <span>Material de Apoio (PDFs)</span>
                <span className="text-xs text-gray-400 dark:text-gray-500 font-normal border border-gray-200 dark:border-gray-700 px-2 py-0.5 rounded-full">Opcional</span>
              </label>

              <div className="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl p-4 text-center hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors relative mb-4 group cursor-pointer">
                <input
                  type="file"
                  multiple
                  accept="application/pdf"
                  onChange={handleFileChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                />
                <div className="transform group-hover:scale-105 transition-transform duration-300 flex flex-col items-center">
                  <UploadCloud className="w-8 h-8 text-gray-400 dark:text-gray-500 mb-1 group-hover:text-indigo-500" />
                  <p className="text-xs text-gray-600 dark:text-gray-300 font-medium">Arraste PDFs aqui</p>
                </div>
              </div>

              {/* File List */}
              {storedFiles.length > 0 && (
                <div className="bg-gray-50 dark:bg-gray-900/30 rounded-lg p-3 max-h-32 overflow-y-auto custom-scrollbar border border-gray-100 dark:border-gray-700 mb-4">
                  <div className="space-y-2">
                    {storedFiles.map((file, idx) => (
                      <div key={idx} className="flex items-center justify-between p-2 bg-white dark:bg-gray-800 rounded border border-gray-200 dark:border-gray-700 shadow-sm">
                        <div className="flex items-center space-x-3 overflow-hidden">
                          <FileText className="w-4 h-4 text-indigo-500 dark:text-indigo-400 flex-shrink-0" />
                          <span className="text-xs text-gray-700 dark:text-gray-200 truncate">{file.name}</span>
                        </div>
                        {file.id && (
                          <button onClick={() => handleRemoveFile(file.id!)} className="text-gray-400 hover:text-red-500 dark:hover:text-red-400 transition ml-2">
                            <Trash2 className="w-3 h-3" />
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

             {/* Context Input */}
            <div>
               <textarea
                value={context}
                onChange={(e) => setContext(e.target.value)}
                placeholder="Dica extra: Ex: 'Quero focar em Direito Constitucional' ou 'Gere perguntas difíceis'..."
                className="w-full p-3 text-sm border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-lg text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none resize-none h-16 placeholder-gray-400 transition-colors"
              />
            </div>

            <button
              onClick={handleStartWrapper}
              disabled={isLoading}
              className={`w-full py-4 rounded-xl font-bold text-lg text-white shadow-lg transition-all transform hover:-translate-y-1 active:translate-y-0 flex items-center justify-center ${
                isLoading 
                  ? 'bg-gray-400 dark:bg-gray-600 cursor-wait' 
                  : 'bg-indigo-600 hover:bg-indigo-700 dark:bg-indigo-600 dark:hover:bg-indigo-500'
              }`}
            >
              {isLoading ? (
                <div className="flex items-center">
                  <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white mr-2"></div>
                  <span>Gerando Simulado...</span>
                </div>
              ) : (
                  "Iniciar Simulado Agora"
              )}
            </button>
          </div>
        </div>

        {/* Right Panel (Side items) */}
        <div className="space-y-6 md:col-span-1">

          {/* Review Card */}
          <div className="bg-gradient-to-b from-amber-50 to-orange-50 dark:from-gray-800 dark:to-gray-800 border border-amber-200 dark:border-amber-700/50 p-6 rounded-2xl shadow-xl flex flex-col relative overflow-hidden">
            <div className="absolute top-0 right-0 -mr-8 -mt-8 w-32 h-32 bg-amber-400/20 rounded-full blur-2xl pointer-events-none"></div>

            <div className="flex items-center space-x-2 mb-4 relative z-10">
              <BrainCircuit className="w-6 h-6 text-amber-600 dark:text-amber-500" />
              <h3 className="text-lg font-bold text-gray-800 dark:text-white">Banco de Erros</h3>
            </div>

            <div className="flex-grow flex flex-col justify-center items-center text-center space-y-2 relative z-10 py-4">
              <div className="text-4xl font-extrabold text-amber-600 dark:text-amber-500">
                {errorQuestions.length}
              </div>
              <p className="text-xs text-gray-600 dark:text-gray-300 font-medium px-2">
                Questões pendentes.
              </p>
            </div>

            <div className="mt-2 relative z-10">
              <button
                onClick={handleReviewWrapper}
                disabled={errorQuestions.length === 0 || isLoading}
                className={`w-full py-3 rounded-xl font-bold text-white text-sm shadow-md transition-all transform hover:-translate-y-1 ${
                  errorQuestions.length === 0
                    ? 'bg-gray-300 dark:bg-gray-700 cursor-not-allowed text-gray-500'
                    : 'bg-amber-500 hover:bg-amber-600'
                }`}
              >
                Revisar Erros
              </button>
            </div>
          </div>

          {/* History Card */}
          <div className="bg-white dark:bg-gray-800 border border-gray-100 dark:border-gray-700 p-6 rounded-2xl shadow-lg flex flex-col relative overflow-hidden">
            <div className="flex items-center space-x-2 mb-4">
              <History className="w-6 h-6 text-purple-600 dark:text-purple-400" />
              <h3 className="text-lg font-bold text-gray-800 dark:text-white">Histórico Recente</h3>
            </div>

            <div className="space-y-3">
              {recentHistory.length === 0 ? (
                 <p className="text-sm text-gray-400 italic text-center py-4">Nenhum simulado recente.</p>
              ) : (
                recentHistory.map((item, idx) => (
                  <button 
                    key={idx}
                    onClick={() => onViewHistory(item)}
                    className="w-full text-left p-3 rounded-xl bg-gray-50 dark:bg-gray-700/50 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors border border-gray-100 dark:border-gray-600 flex justify-between items-center group"
                  >
                    <div className="overflow-hidden">
                      <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">{new Date(item.date).toLocaleDateString('pt-BR')}</p>
                      <p className="text-sm font-semibold text-gray-800 dark:text-white truncate">
                        {item.profile ? `${item.profile.cargo}` : 'Simulado Antigo'}
                      </p>
                    </div>
                    <div className="text-right flex-shrink-0 ml-2">
                      <span className={`text-xs px-2 py-0.5 rounded-full font-bold block mb-1 ${
                        item.score >= 70 ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300'
                      }`}>
                        {item.score}%
                      </span>
                    </div>
                  </button>
                ))
              )}
            </div>
          </div>

        </div>

      </div>
    </div>
  );
};

export default UploadSection;

// Removed static Role enum to allow dynamic inputs
export interface ExamProfile {
  banca: string;
  cargo: string;
  escolaridade: 'Fundamental' | 'Médio' | 'Superior';
  qCount: 10 | 20 | 30 | 40; // New field for question quantity
}

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctIndex: number;
  explanation: string;
  topic: string;
}

export interface AnswerAttempt {
  questionId: string;
  selectedIndex: number;
  timeSpentSeconds: number;
  isCorrect: boolean;
}

export interface QuizSession {
  questions: Question[];
  answers: AnswerAttempt[];
  startTime: number;
  endTime?: number;
}

export interface UploadedFile {
  id?: string;
  name: string;
  mimeType: string;
  data: string; // Base64
  dateAdded?: number;
}

export enum AppView {
  HOME = 'HOME',
  QUIZ = 'QUIZ',
  RESULTS = 'RESULTS',
  LOADING = 'LOADING',
}

export interface StrategicAnalysis {
  strengths: string[];
  weaknesses: string[];
  bancaPattern: string;
  recommendations: string;
}

export interface HistoryItem {
  id: number;
  date: number;
  profile: ExamProfile; 
  score: number;
  totalQuestions: number;
  totalTimeSeconds: number;
  analysis: StrategicAnalysis;
  questions?: Question[];
  answers?: AnswerAttempt[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { UploadedFile, ExamProfile, Question, HistoryItem, StrategicAnalysis } from '../types';
import { saveFile, getFiles, deleteFile, getErrorQuestions, getHistory } from '../services/storageService';
import { UploadCloud, FileText, Trash2, BookOpen, BrainCircuit, Play, Flame, History, Building2, Briefcase, GraduationCap, Trophy, Target, Clock, TrendingUp, Lightbulb, ListOrdered } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, CartesianGrid } from 'recharts';

interface UploadSectionProps {
  onStart: (profile: ExamProfile, files: UploadedFile[], context: string) => void;
  onStartReview: (questions: Question[]) => void;
  onViewHistory: (item: HistoryItem) => void;
  isLoading: boolean;
}

const COLORS = {
  high: '#10B981', // Green
  mid: '#F59E0B',  // Amber
  low: '#EF4444',  // Red
};

const UploadSection: React.FC<UploadSectionProps> = ({ onStart, onStartReview, onViewHistory, isLoading }) => {
  // State for Dynamic Inputs
  const [banca, setBanca] = useState('');
  const [cargo, setCargo] = useState('');
  const [escolaridade, setEscolaridade] = useState<'Fundamental' | 'Médio' | 'Superior'>('Médio');
  const [qCount, setQCount] = useState<10 | 20 | 30 | 40>(10); // Default to 10 for quick start

  const [storedFiles, setStoredFiles] = useState<UploadedFile[]>([]);
  const [errorQuestions, setErrorQuestions] = useState<Question[]>([]);
  const [recentHistory, setRecentHistory] = useState<HistoryItem[]>([]);
  const [allHistory, setAllHistory] = useState<HistoryItem[]>([]); // For stats
  const [context, setContext] = useState('');
  const [streak, setStreak] = useState(0);

  // Load everything on mount
  useEffect(() => {
    loadData();
    calculateStreak();
    loadPreferences();
  }, []);

  const loadPreferences = () => {
    const saved = localStorage.getItem('lastExamProfile');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.banca) setBanca(parsed.banca);
        if (parsed.cargo) setCargo(parsed.cargo);
        if (parsed.escolaridade) setEscolaridade(parsed.escolaridade);
        if (parsed.qCount) setQCount(parsed.qCount);
      } catch (e) {
        console.error("Failed to load preferences", e);
      }
    }
  };

  const savePreferences = () => {
    const profile = { banca, cargo, escolaridade, qCount };
    localStorage.setItem('lastExamProfile', JSON.stringify(profile));
  };

  const loadData = async () => {
    try {
      const files = await getFiles();
      setStoredFiles(files);
      const errors = await getErrorQuestions();
      setErrorQuestions(errors);
      const hist = await getHistory();
      setAllHistory(hist);
      setRecentHistory([...hist].reverse().slice(0, 5));
    } catch (error) {
      console.error("Failed to load data", error);
    }
  };

  const calculateStreak = () => {
    const lastStudy = localStorage.getItem('lastStudyDate');
    const currentStreak = parseInt(localStorage.getItem('studyStreak') || '0', 10);

    if (lastStudy) {
      const lastDate = new Date(parseInt(lastStudy));
      const today = new Date();
      lastDate.setHours(0,0,0,0);
      today.setHours(0,0,0,0);

      const diffTime = Math.abs(today.getTime() - lastDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays <= 1) {
        setStreak(currentStreak);
      } else {
        setStreak(0);
        localStorage.setItem('studyStreak', '0');
      }
    } else {
      setStreak(0);
    }
  };

  const updateStreakOnStart = () => {
    const lastStudy = localStorage.getItem('lastStudyDate');
    const today = new Date();
    today.setHours(0,0,0,0);

    let newStreak = parseInt(localStorage.getItem('studyStreak') || '0', 10);

    if (lastStudy) {
      const lastDate = new Date(parseInt(lastStudy));
      lastDate.setHours(0,0,0,0);
      const diffTime = Math.abs(today.getTime() - lastDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays === 1) {
        newStreak += 1;
      } else if (diffDays > 1) {
        newStreak = 1; 
      }
    } else {
      newStreak = 1; 
    }

    localStorage.setItem('lastStudyDate', Date.now().toString());
    localStorage.setItem('studyStreak', newStreak.toString());
    setStreak(newStreak);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        if (file.type === 'application/pdf' || file.type === 'text/plain') {
          const reader = new FileReader();
          const filePromise = new Promise<UploadedFile>((resolve) => {
            reader.onload = (event) => {
              const base64 = (event.target?.result as string).split(',')[1];
              resolve({ name: file.name, mimeType: file.type, data: base64 });
            };
          });
          const pFile = await filePromise;
          await saveFile(pFile);
        }
      }
      loadData();
    }
  };

  const handleRemoveFile = async (id: string) => {
    if(!id) return;
    await deleteFile(id);
    loadData();
  };

  const handleStartWrapper = () => {
    if (!banca.trim() || !cargo.trim()) {
      alert("Por favor, preencha a Banca e o Cargo para iniciar.");
      return;
    }
    savePreferences(); // Auto-save
    updateStreakOnStart();
    const profile: ExamProfile = { banca, cargo, escolaridade, qCount };
    onStart(profile, storedFiles, context);
  };

  const handleReviewWrapper = () => {
    updateStreakOnStart();
    onStartReview(errorQuestions);
  };

  // --- DASHBOARD CALCULATIONS ---
  const stats = useMemo(() => {
    if (allHistory.length === 0) return null;

    let totalSeconds = 0;
    let totalQuestionsAnswered = 0;
    let totalCorrect = 0;
    const topicStats: Record<string, { correct: number; total: number }> = {};

    allHistory.forEach(h => {
      totalSeconds += h.totalTimeSeconds || 0;
      totalQuestionsAnswered += h.totalQuestions || 0;
      // Estimate correct based on score if answers not present (legacy) or calculate exactly
      const correctInSession = Math.round((h.score / 100) * h.totalQuestions);
      totalCorrect += correctInSession;

      // Aggregating topics
      if (h.questions && h.answers) {
        h.questions.forEach(q => {
          const t = q.topic || 'Geral';
          if (!topicStats[t]) topicStats[t] = { correct: 0, total: 0 };
          topicStats[t].total++;
          const isCorrect = h.answers?.find(a => a.questionId === q.id)?.isCorrect;
          if (isCorrect) topicStats[t].correct++;
        });
      }
    });

    // Calculate Weaknesses and Strengths based on data
    const topicPerformance = Object.entries(topicStats).map(([topic, data]) => ({
      topic,
      percentage: Math.round((data.correct / data.total) * 100),
      total: data.total
    })).sort((a, b) => a.percentage - b.percentage); // Lowest first

    const globalScore = totalQuestionsAnswered > 0 ? Math.round((totalCorrect / totalQuestionsAnswered) * 100) : 0;

    // Get latest recommendations
    const lastSession = allHistory[allHistory.length - 1];
    const latestPlan = lastSession?.analysis?.recommendations || "Realize um simulado para gerar seu plano.";

    return {
      totalHours: Math.floor(totalSeconds / 3600),
      totalMinutes: Math.floor((totalSeconds % 3600) / 60),
      globalScore,
      questionsCount: totalQuestionsAnswered,
      topicPerformance, // Full list for chart
      latestPlan
    };
  }, [allHistory]);

  return (
